mapper.select:
SELECT REQ_ID_CODE
  FROM FWK_LISTENER_TRX_MESSAGE
 WHERE GW_ID = #{gwId}

SELECT TRX_ID
  FROM FWK_LISTENER_TRX_MESSAGE
 WHERE GW_ID       = #{gwId}
   AND REQ_ID_CODE = #{command}

SELECT SERVICE_ID
  FROM FWK_SERVICE
 WHERE TRX_ID  = #{trxId}
   AND ORG_ID  = #{orgId}
   AND IO_TYPE = #{ioType}
   AND USE_YN  = 'Y'

SELECT CP.PARAM_KEY    AS paramKey,
       RP.PARAM_VALUE  AS paramValue
  FROM FWK_RELATION_PARAM  RP
  JOIN FWK_COMPONENT_PARAM CP
    ON RP.COMPONENT_ID = CP.COMPONENT_ID
   AND RP.PARAM_SEQ_NO = CP.PARAM_SEQ_NO
 WHERE RP.SERVICE_ID     = #{serviceId}
   AND RP.SERVICE_SEQ_NO = #{serviceSeqNo}
   AND RP.COMPONENT_ID   = #{componentId}
 ORDER BY RP.PARAM_SEQ_NO ASC
